import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import './ProjectFeed.css';

function ProjectFeed() {
  const [projects, setProjects] = useState([]);
  const [filteredProjects, setFilteredProjects] = useState([]);
  const [loading, setLoading] = useState(true);
  const [skills, setSkills] = useState([]);
  const [filters, setFilters] = useState({
    skill: '',
    minBudget: '',
    maxBudget: ''
  });
  
  const navigate = useNavigate();

  // Fetch all projects on load
  useEffect(() => {
    fetchProjects();
  }, []);

  const fetchProjects = async () => {
    try {
      setLoading(true);
      const token = localStorage.getItem('access');
      
      const response = await axios.get('http://127.0.0.1:8000/api/projects/', {
        headers: { Authorization: `Bearer ${token}` }
      });
      
      // Extract unique skills from all projects
      const allSkills = [];
      response.data.forEach(project => {
        if (project.skills_required) {
          project.skills_required.split(',').forEach(skill => {
            const trimmed = skill.trim();
            if (trimmed && !allSkills.includes(trimmed)) {
              allSkills.push(trimmed);
            }
          });
        }
      });
      
      setSkills(allSkills);
      setProjects(response.data);
      setFilteredProjects(response.data);
      setLoading(false);
    } catch (error) {
      console.error('Error fetching projects:', error);
      setLoading(false);
    }
  };

  // Apply filters
  const applyFilters = () => {
    let filtered = [...projects];
    
    // Filter by skill
    if (filters.skill) {
      filtered = filtered.filter(project => 
        project.skills_required && 
        project.skills_required.toLowerCase().includes(filters.skill.toLowerCase())
      );
    }
    
    // Filter by min budget
    if (filters.minBudget) {
      filtered = filtered.filter(project => 
        parseFloat(project.budget_min) >= parseFloat(filters.minBudget)
      );
    }
    
    // Filter by max budget
    if (filters.maxBudget) {
      filtered = filtered.filter(project => 
        parseFloat(project.budget_max) <= parseFloat(filters.maxBudget)
      );
    }
    
    setFilteredProjects(filtered);
  };

  // Handle filter input changes
  const handleFilterChange = (e) => {
    setFilters({
      ...filters,
      [e.target.name]: e.target.value
    });
  };

  // Calculate time ago
  const getTimeAgo = (dateString) => {
    const now = new Date();
    const past = new Date(dateString);
    const diffTime = Math.abs(now - past);
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
    
    if (diffDays === 0) return 'Today';
    if (diffDays === 1) return 'Yesterday';
    return `${diffDays} days ago`;
  };

  if (loading) return <div className="loading">Loading projects...</div>;

  return (
    <div className="project-feed-container">
      <h1>🔷 Available Projects</h1>
      
      {/* Filter Section */}
      <div className="filter-section">
        <select 
          name="skill" 
          value={filters.skill} 
          onChange={handleFilterChange}
          className="filter-select"
        >
          <option value="">All Skills</option>
          {skills.map(skill => (
            <option key={skill} value={skill}>{skill}</option>
          ))}
        </select>
        
        <input
          type="number"
          name="minBudget"
          placeholder="Min Budget"
          value={filters.minBudget}
          onChange={handleFilterChange}
          className="filter-input"
        />
        
        <input
          type="number"
          name="maxBudget"
          placeholder="Max Budget"
          value={filters.maxBudget}
          onChange={handleFilterChange}
          className="filter-input"
        />
        
        <button onClick={applyFilters} className="filter-btn">
          Apply Filters
        </button>
      </div>

      {/* Results count */}
      <p className="results-count">Showing {filteredProjects.length} projects</p>

      {/* Projects Grid */}
      <div className="projects-grid">
        {filteredProjects.length > 0 ? (
          filteredProjects.map(project => (
            <div key={project.id} className="project-card">
              <h3>{project.title}</h3>
              <p className="description">
                {project.description.length > 100 
                  ? `${project.description.substring(0, 100)}...` 
                  : project.description}
              </p>
              
              <div className="project-details">
                <p><span>💰</span> ₹{project.budget_min} - ₹{project.budget_max}</p>
                <p><span>🛠️</span> {project.skills_required}</p>
                <p><span>⏱️</span> {project.duration_days} days</p>
                <p><span>📨</span> {project.proposals_count || 0} proposals</p>
                <p><span>🕒</span> {getTimeAgo(project.created_at)}</p>
              </div>
              
              <button 
                className="view-btn"
                onClick={() => navigate(`/projects/${project.id}`)}
              >
                View Details →
              </button>
            </div>
          ))
        ) : (
          <p className="no-results">No projects match your filters</p>
        )}
      </div>
    </div>
  );
}

export default ProjectFeed;
